import { useEffect, useMemo, useState } from 'react';

import type { Element } from '@bim-ai/core';

import { Btn } from '@bim-ai/ui';

import type { PlanProjectionPrimitivesV1Wire } from '../plan/planProjectionWire';

import {
  buildRoomSeparationWorkbenchReadout,
  validateAxisAlignedSeparationSegmentMm,
} from './roomSeparationWorkbenchReadout';

type LevelRow = Extract<Element, { kind: 'level' }>;

type Props = {
  selected: Element | undefined;
  elementsById: Record<string, Element>;
  wirePrimitives: PlanProjectionPrimitivesV1Wire | null;
  levels: LevelRow[];
  defaultLevelId: string;
  revision: number;
  onUpsertSemantic: (cmd: Record<string, unknown>) => void;
};

export function RoomSeparationAuthoringWorkbench({
  selected,
  elementsById,
  wirePrimitives,
  levels,
  defaultLevelId,
  revision,
  onUpsertSemantic,
}: Props) {
  const readout = useMemo(() => {
    if (!selected || selected.kind !== 'room_separation') return null;
    return buildRoomSeparationWorkbenchReadout(selected, elementsById, wirePrimitives);
  }, [selected, elementsById, wirePrimitives]);

  const [levelId, setLevelId] = useState(defaultLevelId);

  useEffect(() => {
    setLevelId(defaultLevelId);
  }, [defaultLevelId]);
  const [nameDraft, setNameDraft] = useState('Separation');
  const [sx, setSx] = useState('0');
  const [sy, setSy] = useState('0');
  const [ex, setEx] = useState('2000');
  const [ey, setEy] = useState('0');
  const [authorError, setAuthorError] = useState<string | null>(null);

  const lv0 = levels[0]?.id ?? '';
  const effectiveLevelId = levelId || lv0;

  return (
    <div
      className="border-border mb-3 space-y-2 border-b pb-3 text-[11px]"
      data-testid="room-separation-authoring-workbench"
    >
      <div className="font-semibold text-muted">Room separation</div>

      {readout ? (
        <div className="space-y-1 rounded border border-border bg-muted/15 p-2 text-[10px]" data-testid="room-separation-readout">
          <div>
            <span className="text-muted">Name · id:</span>{' '}
            <span className="font-medium">{readout.name}</span>
            <span className="font-mono text-muted"> · {readout.id}</span>
          </div>
          <div>
            <span className="text-muted">Level:</span> {readout.levelName}{' '}
            <span className="font-mono text-muted">({readout.levelId})</span>
          </div>
          <div className="font-mono text-[9px]">
            start ({readout.startXMm}, {readout.startYMm}) → end ({readout.endXMm}, {readout.endYMm}) · length{' '}
            {readout.lengthMm} mm
          </div>
          <div>
            <span className="text-muted">Axis-aligned pool:</span>{' '}
            {readout.axisAlignedBoundarySegmentEligible ? 'eligible' : 'excluded'}
            {readout.axisBoundarySegmentExcludedReason
              ? ` (${readout.axisBoundarySegmentExcludedReason})`
              : ''}
          </div>
          <div>
            <span className="text-muted">Authoritative perimeter:</span>{' '}
            {readout.onAuthoritativeDerivedFootprintBoundary ? 'yes' : 'no'}
          </div>
          <div>
            <span className="text-muted">Pierces derived interior:</span>{' '}
            {readout.piercesDerivedRectangleInterior ? 'yes' : 'no'}
          </div>
        </div>
      ) : (
        <div className="rounded border border-dashed border-border p-2 text-[10px] text-muted">
          Select a room separation line to inspect derivation flags (plan wire augments readout).
        </div>
      )}

      <div className="text-[10px] font-medium text-muted">Add axis-aligned segment</div>
      <div className="grid grid-cols-2 gap-2 text-[10px]" key={`rs-author-${revision}`}>
        <label className="block text-muted">
          Level
          <select
            className="mt-1 w-full rounded border border-border bg-background px-1 py-1 font-mono text-[10px]"
            value={effectiveLevelId}
            onChange={(e) => setLevelId(e.target.value)}
          >
            {levels.map((l) => (
              <option key={l.id} value={l.id}>
                {l.name}
              </option>
            ))}
          </select>
        </label>
        <label className="block text-muted">
          Name
          <input
            className="mt-1 w-full rounded border border-border bg-background px-2 py-1 font-mono text-[11px]"
            value={nameDraft}
            onChange={(e) => setNameDraft(e.target.value)}
          />
        </label>
        <label className="block text-muted">
          Start X mm
          <input
            className="mt-1 w-full rounded border border-border bg-background px-2 py-1 font-mono text-[11px]"
            value={sx}
            onChange={(e) => setSx(e.target.value)}
          />
        </label>
        <label className="block text-muted">
          Start Y mm
          <input
            className="mt-1 w-full rounded border border-border bg-background px-2 py-1 font-mono text-[11px]"
            value={sy}
            onChange={(e) => setSy(e.target.value)}
          />
        </label>
        <label className="block text-muted">
          End X mm
          <input
            className="mt-1 w-full rounded border border-border bg-background px-2 py-1 font-mono text-[11px]"
            value={ex}
            onChange={(e) => setEx(e.target.value)}
          />
        </label>
        <label className="block text-muted">
          End Y mm
          <input
            className="mt-1 w-full rounded border border-border bg-background px-2 py-1 font-mono text-[11px]"
            value={ey}
            onChange={(e) => setEy(e.target.value)}
          />
        </label>
      </div>
      {authorError ? (
        <div className="rounded border border-destructive/40 bg-destructive/10 p-1.5 text-[10px] text-destructive">
          {authorError}
        </div>
      ) : null}
      <Btn
        type="button"
        className="w-full text-[11px]"
        onClick={() => {
          const x0 = Number(sx);
          const y0 = Number(sy);
          const x1 = Number(ex);
          const y1 = Number(ey);
          if (![x0, y0, x1, y1].every((n) => Number.isFinite(n))) {
            setAuthorError('Enter numeric coordinates.');
            return;
          }
          if (!effectiveLevelId) {
            setAuthorError('No level in model.');
            return;
          }
          const v = validateAxisAlignedSeparationSegmentMm(x0, y0, x1, y1);
          if (!v.ok) {
            setAuthorError(v.message);
            return;
          }
          setAuthorError(null);
          onUpsertSemantic({
            type: 'createRoomSeparation',
            levelId: effectiveLevelId,
            name: nameDraft.trim() || 'Separation',
            start: { xMm: x0, yMm: y0 },
            end: { xMm: x1, yMm: y1 },
          });
        }}
      >
        createRoomSeparation
      </Btn>
    </div>
  );
}

import { useMemo } from 'react';

import type { Element, Violation } from '@bim-ai/core';

import { recommendedContextForRuleId } from '../advisor/advisorViolationContext';
import { useBimStore } from '../state/store';

import {
  buildLevelDatumStackEvidenceToken,
  buildLevelDatumStackRows,
  filterDatumWorkbenchViolations,
  formatElevationMmReadout,
  levelIdsFromDatumRows,
} from './datumLevelStackReadout';
import { formatLevelDatumPropagationEvidenceLine } from './levelDatumPropagationReadout';

type Props = {
  selected: Element | undefined;
  elementsById: Record<string, Element>;
  violations: Violation[];
};

export function LevelDatumStackWorkbench({ selected, elementsById, violations }: Props) {
  const rows = useMemo(() => buildLevelDatumStackRows(elementsById), [elementsById]);
  const levelIds = useMemo(() => levelIdsFromDatumRows(rows), [rows]);
  const lastPropagation = useBimStore((s) => s.lastLevelElevationPropagationEvidence);

  const datumViolations = useMemo(
    () => filterDatumWorkbenchViolations(violations, levelIds),
    [violations, levelIds],
  );

  if (!selected || selected.kind !== 'level') {
    return null;
  }

  const evidence = buildLevelDatumStackEvidenceToken(rows, selected.id);

  return (
    <div
      className="border-border mb-3 space-y-2 border-b pb-3 text-[11px]"
      data-testid="level-datum-stack-workbench"
    >
      <div className="font-semibold text-muted">Level / datum stack</div>
      <div className="text-[10px] leading-snug text-muted">
        Read-only stack from snapshot; elevation aligns parent+offset within{' '}
        <span className="font-mono">±1</span> mm → <span className="font-mono">derived</span>.
      </div>

      {rows.length ? (
        <div className="max-h-48 overflow-auto rounded border border-border">
          <table className="w-full border-collapse text-left text-[10px]">
            <thead>
              <tr className="border-border border-b bg-muted/40">
                <th className="p-1.5 font-medium">Level</th>
                <th className="p-1.5 font-medium text-right">Abs. el. (mm)</th>
                <th className="p-1.5 font-medium">Parent</th>
                <th className="p-1.5 font-medium text-right">Offset (mm)</th>
                <th className="p-1.5 font-medium">Token</th>
                <th className="p-1.5 font-medium text-right">Plans</th>
              </tr>
            </thead>
            <tbody>
              {rows.map((row) => {
                const isSel = row.id === selected.id;
                return (
                  <tr
                    key={row.id}
                    className={
                      isSel
                        ? 'border-border border-b bg-muted/25 odd:bg-muted/20 even:bg-muted/15'
                        : 'border-border border-b odd:bg-background even:bg-muted/15 last:border-b-0'
                    }
                  >
                    <td className="p-1.5">
                      <div className="max-w-[7rem] truncate font-medium" title={row.name}>
                        {row.name}
                      </div>
                      <div className="font-mono text-[9px] text-muted">{row.id}</div>
                    </td>
                    <td className="p-1.5 text-right font-mono">{formatElevationMmReadout(row.elevationMm)}</td>
                    <td className="max-w-[6rem] p-1.5">
                      {row.parentLevelId ? (
                        <>
                          <div className="truncate" title={row.parentName ?? row.parentLevelId}>
                            {row.parentName ?? '—'}
                          </div>
                          <div className="truncate font-mono text-[9px] text-muted">{row.parentLevelId}</div>
                        </>
                      ) : (
                        <span className="text-muted">—</span>
                      )}
                    </td>
                    <td className="p-1.5 text-right font-mono">
                      {row.parentLevelId ? formatElevationMmReadout(row.offsetFromParentMm) : '—'}
                    </td>
                    <td className="p-1.5 font-mono">{row.elevationToken}</td>
                    <td className="p-1.5 text-right font-mono">{row.planViewCount}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      ) : (
        <div className="rounded border border-dashed border-border p-2 text-[10px] text-muted">
          No levels in this snapshot.
        </div>
      )}

      {datumViolations.length ? (
        <div className="space-y-1.5">
          <div className="text-[10px] font-medium text-muted">Datum-related advisories</div>
          <ul className="space-y-1 text-[10px]">
            {datumViolations.map((v) => (
              <li
                key={`${v.ruleId}:${v.severity}:${v.message}:${(v.elementIds ?? []).join(',')}`}
                className="rounded border border-border bg-muted/20 p-1.5"
              >
                <div className="font-mono text-[9px] text-muted">
                  {v.severity} · {v.ruleId}
                </div>
                <div className="text-foreground">{v.message}</div>
                {v.elementIds?.length ? (
                  <div className="mt-0.5 font-mono text-[9px] text-muted">
                    ids: {v.elementIds.join(', ')}
                  </div>
                ) : null}
                <div className="mt-0.5 text-[9px] text-muted">{recommendedContextForRuleId(v.ruleId)}</div>
              </li>
            ))}
          </ul>
        </div>
      ) : null}

      {lastPropagation ? (
        <div
          className="break-all rounded border border-border/60 bg-muted/20 p-1.5 font-mono text-[10px] text-muted"
          data-testid="level-datum-propagation-evidence"
        >
          {formatLevelDatumPropagationEvidenceLine(lastPropagation)}
        </div>
      ) : null}

      <div
        className="break-all rounded bg-muted/30 p-1.5 font-mono text-[10px] text-foreground"
        data-testid="level-datum-stack-evidence"
        title="Deterministic summary for agents / evidence"
      >
        {evidence}
      </div>
    </div>
  );
}

