187	      return;
188	    }
189	
190	    let north: number | null = null;
191	    if (northDegText.trim().length > 0) {
192	      const n = Number(northDegText);
193	      if (!Number.isFinite(n)) {
194	        setApplyError('North (deg CW from +X) must be a number when set.');
195	        return;
196	      }
197	      north = n;
