221	        return;
222	      }
223	      const sx = typeof r.scale === 'number' ? r.scale : 1;
224	      if (!Number.isFinite(sx) || sx <= 0) {
225	        setApplyError(`Context '${k}' scale must be > 0 when set (default 1).`);
226	        return;
227	      }
228	      if (!r.positionMm || typeof r.positionMm.xMm !== 'number' || typeof r.positionMm.yMm !== 'number') {
229	        setApplyError(`Context '${k}' positionMm requires numeric xMm and yMm.`);
230	        return;
231	      }
232	    }
233	
234	    const cmd = buildUpsertSiteCmdPayload({
235	      id: idTrim,
236	      name: name.trim() || 'Site',
237	      referenceLevelId: rid,
238	      boundaryMm: boundaryMmFromAnchorSize(
239	        anchor,
240	        Number(widthMm),
241	        Number(depthMm),
242	      ),
243	      padThicknessMm: pad,
244	      baseOffsetMm: bo,
245	      northDegCwFromPlanX: north,
246	      uniformSetbackMm: setback,
247	      contextObjects: payloads,
248	    });
249	    onUpsertSemantic(cmd);
250	  };
251	
252	  return (
253	    <Panel title="Site (pad boundary)">
254	      <div className="space-y-3 text-[11px]">
255	        <div className="rounded border border-border bg-muted/20 p-2 text-[10px] text-muted">
256	          <strong className="text-foreground">Evidence</strong> — boundary vertices{' '}
257	          <span className="font-mono">{boundaryMmResolved.length}</span>, context markers{' '}
258	          <span className="font-mono">{evidenceContextCount}</span>, ref level{' '}
259	          <span className="font-mono">{refLevelName}</span>. Bounded to{' '}
260	          <span className="font-mono">upsertSite</span>; no grading, contours, or survey import — pad
261	          is a simple prism.
262	        </div>
263	
264	        <div className="grid grid-cols-2 gap-2">
265	          <label className="flex min-w-0 flex-col text-[10px] text-muted">
266	            Site id
267	            <input
268	              className="mt-0.5 rounded border border-border bg-background px-1 py-0.5 font-mono text-[10px]"
269	              value={siteId}
270	              onChange={(e) => setSiteId(e.target.value)}
271	            />
272	          </label>
273	          <label className="flex min-w-0 flex-col text-[10px] text-muted">
274	            Name
275	            <input
276	              className="mt-0.5 rounded border border-border bg-background px-1 py-0.5 font-mono text-[10px]"
277	              value={name}
278	              onChange={(e) => setName(e.target.value)}
279	            />
280	          </label>
281	        </div>
282	
283	        <label className="flex min-w-0 flex-col text-[10px] text-muted">
284	          Reference level
285	          <select
286	            className="mt-0.5 rounded border border-border bg-background px-1 py-0.5 font-mono text-[10px]"
287	            value={referenceLevelId}
288	            onChange={(e) => setReferenceLevelId(e.target.value)}
289	          >
290	            <option value="">—</option>
291	            {levels.map((l) => (
292	              <option key={l.id} value={l.id}>
293	                {l.name} ({l.id})
294	              </option>
295	            ))}
296	          </select>
297	        </label>
298	
299	        <div className="grid grid-cols-2 gap-2">
300	          <label className="flex min-w-0 flex-col text-[10px] text-muted">
301	            Anchor X (mm)
302	            <input
303	              className="mt-0.5 rounded border border-border bg-background px-1 py-0.5 font-mono text-[10px]"
304	              type="number"
305	              value={anchor.xMm}
306	              onChange={(e) =>
307	                setAnchor((a) => ({ ...a, xMm: Number(e.target.value) || 0 }))
308	              }
309	            />
310	          </label>
311	          <label className="flex min-w-0 flex-col text-[10px] text-muted">
312	            Anchor Y (mm)
313	            <input
314	              className="mt-0.5 rounded border border-border bg-background px-1 py-0.5 font-mono text-[10px]"
315	              type="number"
316	              value={anchor.yMm}
317	              onChange={(e) =>
318	                setAnchor((a) => ({ ...a, yMm: Number(e.target.value) || 0 }))
319	              }
320	            />
321	          </label>
322	        </div>
323	
324	        <div className="grid grid-cols-2 gap-2">
325	          <label className="flex min-w-0 flex-col text-[10px] text-muted">
