586	      { id: 'settings.theme.light', kind: 'setting', label: 'Theme: light', keywords: 'light' },
587	      { id: 'settings.theme.dark', kind: 'setting', label: 'Theme: dark', keywords: 'dark' },
588	    );
589	    // Agent
590	    items.push({ id: 'agent.review', kind: 'agent', label: 'Run Agent Review' });
591	    return items;
592	  }, [elementsById]);
593	
594	  const handlePalettePick = useCallback(
595	    (cand: CommandCandidate) => {
596	      setRecentCommandIds((prev) => [cand.id, ...prev.filter((id) => id !== cand.id)].slice(0, 5));
597	      if (cand.kind === 'tool') {
598	        const toolId = cand.id.replace(/^tool\./, '') as ToolId;
599	        const legacy = toolIdToLegacy(toolId);
600	        if (legacy) setPlanTool(legacy);
601	        return;
602	      }
603	      if (cand.kind === 'element') {
604	        select(cand.id);
605	        return;
606	      }
607	      if (cand.id === 'settings.theme.light' || cand.id === 'settings.theme.dark') {
608	        const next = cand.id.endsWith('dark') ? 'dark' : 'light';
609	        if (getCurrentTheme() !== next) {
610	          toggleTheme();
611	          setTheme(next as Theme);
612	        }
613	        return;
614	      }
615	      if (cand.kind === 'view') {
616	        select(cand.id);
617	      }
618	    },
619	    [select, setPlanTool],
620	  );
621	
622	  /* ── Empty-state per §25 ──────────────────────────────────────────── */
623	  const emptyHint = patternFor('canvas-empty');
624	  const showEmptyState =
625	    (Object.values(elementsById) as Element[]).filter((e) => e.kind === 'wall').length === 0;
626	
627	  /* ── Compose AppShell slots ───────────────────────────────────────── */
628	  return (
629	    <>
630	      <CheatsheetModal open={cheatsheetOpen} onClose={() => setCheatsheetOpen(false)} />
631	      <RedesignedCommandPalette
632	        open={paletteOpen}
633	        onOpenChange={setPaletteOpen}
634	        candidates={paletteCandidates}
635	        recentIds={recentCommandIds}
636	        onPick={handlePalettePick}
637	      />
638	      <OnboardingTour open={tourOpen} onClose={() => setTourOpen(false)} />
639	      <ProjectMenu
640	        open={projectMenuOpen}
641	        onOpenChange={setProjectMenuOpen}
642	        anchorRef={projectNameRef}
643	        recent={recentProjects}
644	        onPickRecent={handlePickRecent}
645	        onInsertSeed={() => void insertSeedHouse()}
646	        onSaveSnapshot={handleSaveSnapshot}
647	        onRestoreSnapshot={(f) => void handleRestoreSnapshot(f)}
648	        onNewClear={handleNewClear}
649	        onReplayTour={() => {
650	          resetOnboarding();
651	          setTourOpen(true);
652	        }}
653	      />
654	      <AppShell
655	        topBar={
656	          <div className="flex w-full flex-col">
657	            <div className="flex w-full items-center">
658	              <TopBar
