244	        const restored = t.viewportState?.orbitCameraPoseMm;
245	        if (restored?.eyeMm && restored.targetMm) {
246	          useBimStore.getState().setOrbitCameraFromViewpointMm({
247	            position: restored.eyeMm,
248	            target: restored.targetMm,
249	            up: { xMm: 0, yMm: 1, zMm: 0 },
250	          });
251	        }
252	        // Capture the incoming plan camera for post-setState apply (plan-to-plan case).
253	        if (t.kind === 'plan' || t.kind === 'plan-3d') {
254	          pendingPlanCamera = t.viewportState?.planCamera;
255	        }
256	        return next;
257	      });
258	
259	      // Apply plan camera to the already-mounted PlanCanvas (plan-to-plan switch).
260	      // For 3D→plan switches, initialCamera prop handles restore at mount time.
261	      if (pendingPlanCamera) {
262	        planCameraHandleRef.current?.applySnapshot(pendingPlanCamera);
263	      }
264	    },
265	    [setActiveLevelId],
266	  );
267	
268	  const handleTabClose = useCallback((id: string) => {
269	    setTabsState((s) => closeTab(s, id));
270	  }, []);
271	
272	  const openTabFromElement = useCallback((el: Element) => {
273	    const partial = tabFromElement(el);
274	    if (!partial) return;
275	    setTabsState((s) => openTab(s, partial));
276	  }, []);
277	
